294→    /**
295→     * Set the set tags of currentNote to tagsList.  We make no
296→     * assumption on the content of tagsList, except that its strings
297→     * are valid tags (i.e. no spaces in it).
298→     */
299→    private fun setTags(currentNote: Note, tagsList: List<String>?) {
300→        val currentTags = currentNote.tags.toTypedArray()
301→        for (tag in currentTags) {
302→            currentNote.delTag(tag)
303→        }
304→        if (tagsList != null) {
305→            val tagsSet = currentNote.col.tags.canonify(tagsList)
306→            currentNote.addTags(tagsSet)
307→        }
308→    }
