319→    private fun getBundleEditFields(noteEditorBundle: Bundle?): MutableList<String> {
320→        val noteFields = noteEditorBundle!!.getBundle("editFields")
321→            ?: return mutableListOf()
322→        // we map from "int" -> field, but the order isn't guaranteed, and there may be skips.
323→        // so convert this to a list of strings, with null in place of the invalid fields
324→        val elementCount = noteFields.keySet().stream().map { s: String -> s.toInt() }.max { obj: Int, anotherInteger: Int? -> obj.compareTo(anotherInteger!!) }.orElse(-1) + 1
325→        val ret = Array(elementCount) { "" } // init array, nulls cause a crash
326→        for (fieldOrd in noteFields.keySet()) {
327→            ret[fieldOrd.toInt()] = noteFields.getString(fieldOrd)!!
328→        }
329→        return mutableListOf(*ret)
330→    }
